import { useState } from "react";
import { useAuth } from "../context/AuthContext";

const API = import.meta.env.VITE_API_URL || "";

export default function LoginPage() {
  const { login } = useAuth();
  const [tab, setTab] = useState("login"); // "login" | "signup"
  const [form, setForm] = useState({ username: "", password: "", role: "viewer" });
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);

  const update = (e) => setForm(f => ({ ...f, [e.target.name]: e.target.value }));

  const handleLogin = async () => {
    setLoading(true); setError("");
    try {
      const res = await fetch(`${API}/auth/login`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ username: form.username, password: form.password }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Login failed");
      login(data);
    } catch (e) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  };

  const handleSignup = async () => {
    setLoading(true); setError(""); setSuccess("");
    try {
      const res = await fetch(`${API}/auth/signup`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Signup failed");
      setSuccess("Account created! You can now sign in.");
      setTab("login");
      setForm(f => ({ ...f, password: "" }));
    } catch (e) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={s.page}>
      <div style={s.card}>
        <div style={s.logo}>M</div>
        <h2 style={s.title}>Maruti Group</h2>
        <p style={s.sub}>Transport Management System</p>

        {/* Tabs */}
        <div style={s.tabs}>
          <button
            style={{ ...s.tabBtn, ...(tab === "login" ? s.tabActive : {}) }}
            onClick={() => { setTab("login"); setError(""); setSuccess(""); }}
          >
            Sign In
          </button>
          <button
            style={{ ...s.tabBtn, ...(tab === "signup" ? s.tabActive : {}) }}
            onClick={() => { setTab("signup"); setError(""); setSuccess(""); }}
          >
            Create Account
          </button>
        </div>

        <input
          style={s.input}
          placeholder="Username"
          name="username"
          value={form.username}
          onChange={update}
        />
        <input
          style={s.input}
          type="password"
          placeholder="Password"
          name="password"
          value={form.password}
          onChange={update}
          onKeyDown={e => e.key === "Enter" && (tab === "login" ? handleLogin() : handleSignup())}
        />

        {/* Role selector only on signup */}
        {tab === "signup" && (
          <select style={s.input} name="role" value={form.role} onChange={update}>
            <option value="viewer">Viewer</option>
            <option value="admin">Admin</option>
          </select>
        )}

        {error   && <p style={s.error}>{error}</p>}
        {success && <p style={s.success}>{success}</p>}

        <button
          style={s.btn}
          onClick={tab === "login" ? handleLogin : handleSignup}
          disabled={loading}
        >
          {loading ? "Please wait..." : tab === "login" ? "Sign In" : "Create Account"}
        </button>
      </div>
    </div>
  );
}

const s = {
  page:    { minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", background: "#f0f4f8" },
  card:    { background: "#fff", padding: "40px 36px", borderRadius: 12, boxShadow: "0 4px 24px rgba(0,0,0,0.1)", width: 340, display: "flex", flexDirection: "column", gap: 12 },
  logo:    { width: 48, height: 48, borderRadius: 12, background: "#1a3a5c", color: "#fff", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 800, fontSize: 22 },
  title:   { margin: 0, fontSize: 20, fontWeight: 700, color: "#1a3a5c" },
  sub:     { margin: 0, fontSize: 13, color: "#888" },
  tabs:    { display: "flex", gap: 4, background: "#f0f4f8", borderRadius: 8, padding: 4 },
  tabBtn:  { flex: 1, padding: "7px", border: "none", borderRadius: 6, cursor: "pointer", fontSize: 13, fontWeight: 500, background: "transparent", color: "#666" },
  tabActive: { background: "#fff", color: "#1a3a5c", fontWeight: 700, boxShadow: "0 1px 4px rgba(0,0,0,0.1)" },
  input:   { padding: "10px 12px", border: "1px solid #d0dce8", borderRadius: 6, fontSize: 14, outline: "none" },
  btn:     { padding: "11px", background: "#1a3a5c", color: "#fff", border: "none", borderRadius: 6, fontSize: 14, fontWeight: 700, cursor: "pointer" },
  error:   { color: "#cc3333", fontSize: 13, margin: 0 },
  success: { color: "#166534", fontSize: 13, margin: 0 },
};
